import json

with open('baseline-packages.json') as f:
    baseline = json.load(f)
with open('after-cpm-packages.json') as f:
    after = json.load(f)

# Build lookup: (project_basename, framework, package_id) -> resolved_version
def build_lookup(data):
    lookup = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                lookup[(name, fw['framework'], pkg['id'])] = pkg['resolvedVersion']
    return lookup

b = build_lookup(baseline)
a = build_lookup(after)

all_keys = sorted(set(b.keys()) | set(a.keys()))

changes = []
unchanged = []

for key in all_keys:
    bv = b.get(key)
    av = a.get(key)
    proj, fw, pkg = key
    if bv != av:
        if bv is None:
            changes.append((proj, fw, pkg, '-', av, 'Added'))
        elif av is None:
            changes.append((proj, fw, pkg, bv, '-', 'Removed'))
        else:
            changes.append((proj, fw, pkg, bv, av, 'Aligned to highest version'))
    else:
        unchanged.append((proj, fw, pkg, bv))

print('=== CHANGES ===')
if changes:
    for c in changes:
        print(f'  {c[0]} ({c[1]}) | {c[2]} | {c[3]} -> {c[4]} | {c[5]}')
else:
    print('  (none)')

print()
print('=== UNCHANGED ===')
for u in unchanged:
    print(f'  {u[0]} ({u[1]}) | {u[2]} | {u[3]}')
"

